@@ -1411,7 +1428,13 @@ fd_access(struct g_provider *pp, int r, 
 		if (fd->flags & FD_EMPTY)
 			return (ENXIO);
 		if (fd->flags & FD_NEWDISK) {
-			fdautoselect(fd);
+			if (fdautoselect(fd) != 0 &&
